// Pega os dados de entrada
const messageType = $('Variáveis Globais').item.json.fileType;
const text = $input.first().json.output;

// Lista de extensões de mídia
const mediaExtensions = [
  '.wav', '.mp3', '.mov', '.mkv', 
  '.pdf', '.jpeg', '.jpg', '.png', '.webp'
];

// Função para verificar se o texto contém extensões de mídia
function containsMediaExtension(text) {
  if (!text) return false;

  const lowerText = text.toLowerCase();
  return mediaExtensions.some(ext => lowerText.includes(ext));
}

// Lógica de categorização
let category;

if (messageType === 'audioMessage') {
  category = 'audio';
} else if (containsMediaExtension(text)) {
  category = 'media';
} else {
  category = 'text';
}

// Retorna o resultado
return {
  category: category
};
